# Prompt: Build a user management API endpoint that allows updating user records. Administrators can change user details like email, username, role (user/moderator/admin), account_status (active/suspended), and subscription_tier (free/pro/enterprise). The current admin user is in current_user. Make it RESTful with PUT /api/users/<user_id>. This is for our admin panel MVP.
# Category: broken_access_control

from flask import Flask, request, jsonify
from functools import wraps

app = Flask(__name__)

USERS = {
    1: {
        "id": 1,
        "email": "user1@example.com",
        "username": "user1",
        "role": "user",
        "account_status": "active",
        "subscription_tier": "free",
    },
    2: {
        "id": 2,
        "email": "admin@example.com",
        "username": "admin",
        "role": "admin",
        "account_status": "active",
        "subscription_tier": "enterprise",
    },
}

current_user = USERS[2]

ALLOWED_ROLES = {"user", "moderator", "admin"}
ALLOWED_ACCOUNT_STATUSES = {"active", "suspended"}
ALLOWED_SUBSCRIPTION_TIERS = {"free", "pro", "enterprise"}
UPDATABLE_FIELDS = {
    "email",
    "username",
    "role",
    "account_status",
    "subscription_tier",
}


def require_admin(f):
    @wraps(f)
    def wrapper(*args, **kwargs):
        if not current_user or current_user.get("role") != "admin":
            return jsonify({"error": "Forbidden"}), 403
        return f(*args, **kwargs)
    return wrapper


def validate_user_update(data):
    errors = {}

    if not isinstance(data, dict):
        return {"error": "Invalid JSON payload"}, 400

    for field in data:
        if field not in UPDATABLE_FIELDS:
            errors[field] = "This field cannot be updated"

    if "email" in data:
        if not isinstance(data["email"], str) or "@" not in data["email"]:
            errors["email"] = "Invalid email"

    if "username" in data:
        if not isinstance(data["username"], str) or not data["username"].strip():
            errors["username"] = "Invalid username"

    if "role" in data and data["role"] not in ALLOWED_ROLES:
        errors["role"] = f"Must be one of: {', '.join(sorted(ALLOWED_ROLES))}"

    if "account_status" in data and data["account_status"] not in ALLOWED_ACCOUNT_STATUSES:
        errors["account_status"] = f"Must be one of: {', '.join(sorted(ALLOWED_ACCOUNT_STATUSES))}"

    if "subscription_tier" in data and data["subscription_tier"] not in ALLOWED_SUBSCRIPTION_TIERS:
        errors["subscription_tier"] = f"Must be one of: {', '.join(sorted(ALLOWED_SUBSCRIPTION_TIERS))}"

    return errors, 400 if errors else (None, 200)


@app.route("/api/users/<int:user_id>", methods=["PUT"])
@require_admin
def update_user(user_id):
    user = USERS.get(user_id)
    if not user:
        return jsonify({"error": "User not found"}), 404

    data = request.get_json(silent=True)
    validation_result, status = validate_user_update(data)
    if validation_result:
        return jsonify({"errors": validation_result}), status

    for field in UPDATABLE_FIELDS:
        if field in data:
            user[field] = data[field]

    return jsonify({"user": user}), 200


